const round = gameData.rounds[String(currentRound)];
if (!round) return "No data available for the current round.";

// Helper to get human-readable region names from gameData.regionData
const getRegionName = (regionID) => gameData.regionData[regionID]?.name || regionID;

const allRegionIDs = Object.keys(mapGeometry.geometry);
const occupiedRegionNamesSet = new Set();
const countriesData = [];

// Build a map of regionID to owning country for features with ownerName === undefined
const regionToCountry = {};
for (const countryName in round.countryDescriptions) {
  const country = round.countryDescriptions[countryName];
  for (const regionID of country.regionsOwned) {
    regionToCountry[regionID] = countryName;
  }
}

for (const countryName in round.countryDescriptions) {
  const country = round.countryDescriptions[countryName];
  const ownedRegionsHumanReadable = country.regionsOwned.map(getRegionName).sort();
  ownedRegionsHumanReadable.forEach(regionName => occupiedRegionNamesSet.add(regionName));

  const mapFeatures = [];
  for (const featureID in round.mapFeatures) {
    const feature = round.mapFeatures[featureID];

    // Skip features tagged with 'city'
    if (Array.isArray(feature.tags) && feature.tags.includes("city")) {
      continue;
    }

    // Determine if this feature belongs to the current country
    let belongsToCountry = false;

    if (feature.ownerName === countryName) {
      // Explicitly owned by this country
      belongsToCountry = true;
    } else if (feature.ownerName === undefined) {
      // Owned by whoever owns the region it's in
      const featureRegionID = feature.location.regionID;
      if (featureRegionID && regionToCountry[featureRegionID] === countryName) {
        belongsToCountry = true;
      }
    }
    // If ownerName === null, it's unowned (handled separately at the end)

    if (belongsToCountry) {
      const regionName = getRegionName(feature.location.regionID);
      mapFeatures.push(`"${feature.name}" Stationed in the Region of "${regionName}"`);
    }
  }
  mapFeatures.sort(); // Sort alphabetically

  countriesData.push({
    name: countryName,
    regionsOwned: ownedRegionsHumanReadable,
    mapFeatures: mapFeatures,
    tags: country.tags
  });
}

const MAJOR_NATION_THRESHOLD = 12; // "Major Nations" own more than 12 regions
const majorNations = countriesData
  .filter(c => c.regionsOwned.length > MAJOR_NATION_THRESHOLD)
  .sort((a, b) => a.name.localeCompare(b.name));

const minorNations = countriesData
  .filter(c => c.regionsOwned.length <= MAJOR_NATION_THRESHOLD)
  .sort((a, b) => a.name.localeCompare(b.name));

const output = [];

// Output major nations
for (const nation of majorNations) {
  output.push(`"${nation.name}":`);

  // Only include Tags section if there are tags
  if (nation.tags && nation.tags.length > 0) {
    output.push(`Tags:`);
    output.push(nation.tags.map(tag => `"${tag}"`).join(', '));
  }

  output.push(`All Owned Regions:`);
  if (nation.regionsOwned.length === 0) {
    output.push("none");
  } else {
    output.push(`${nation.regionsOwned.join(", ")}`);
  }

  // Only include Battalions section if there are map features
  if (nation.mapFeatures.length > 0) {
    output.push(`All Battalions:`);
    output.push(nation.mapFeatures.join(", "));
  }

  output.push(""); // Add a blank line for separation
}

// Output minor nations
for (const nation of minorNations) {
  output.push(`"${nation.name}":`);

  // Only include Tags section if there are tags
  if (nation.tags && nation.tags.length > 0) {
    output.push(`Tags:`);
    output.push(nation.tags.map(tag => `"${tag}"`).join(', '));
  }

  output.push(`All Owned Regions:`);
  if (nation.regionsOwned.length === 0) {
    output.push("none");
  } else {
    output.push(`${nation.regionsOwned.join(", ")}`);
  }

  // Only include Battalions section if there are map features
  if (nation.mapFeatures.length > 0) {
    output.push(`All Battalions:`);
    output.push(nation.mapFeatures.join(", "));
  }

  output.push(""); // Add a blank line for separation
}

// Unoccupied regions
const unoccupiedRegionNames = allRegionIDs
  .map(getRegionName)
  .filter(name => !occupiedRegionNamesSet.has(name))
  .sort();

if (unoccupiedRegionNames.length > 0) {
  output.push(`"Unoccupied Regions"`);
  output.push(`${unoccupiedRegionNames.join(", ")}`);
  output.push(""); // Add a blank line for separation
}

// Unowned map features (ownerName === null)
const unownedMapFeatures = [];
for (const featureID in round.mapFeatures) {
  const feature = round.mapFeatures[featureID];

  // Skip features tagged with 'city'
  if (Array.isArray(feature.tags) && feature.tags.includes("city")) {
    continue;
  }

  // Only include features with ownerName === null
  if (feature.ownerName === null) {
    const regionName = feature.location.regionID ? getRegionName(feature.location.regionID) : "Unknown Location";
    unownedMapFeatures.push(`"${feature.name}" Located in "${regionName}"`);
  }
}

if (unownedMapFeatures.length > 0) {
  unownedMapFeatures.sort();
  output.push(`"Unowned Map Features"`);
  output.push(unownedMapFeatures.join(", "));
}

return output.join('\n');

const getFormattedDate = (year, month, day) => {
  const date = new Date(year, month - 1, day);
  const options = { year: 'numeric', month: 'long', day: 'numeric' };
  // Add ordinal suffix to day
  const dayWithSuffix = (d) => {
    if (d > 3 && d < 21) return d + 'th';
    switch (d % 10) {
      case 1: return d + 'st';
      case 2: return d + 'nd';
      case 3: return d + 'rd';
      default: return d + 'th';
    }
  };
  return date.toLocaleDateString('en-US', { month: 'long' }) + ' ' + dayWithSuffix(day) + ', ' + year;
};

let dateToFormat = null;

if (optionalData && optionalData.catalystID) {
  const catalyst = gameData.rounds[String(currentRound)]?.catalysts?.[optionalData.catalystID];
  if (catalyst && catalyst.catalystEvent && catalyst.catalystEvent.date) {
    const eventDateParts = catalyst.catalystEvent.date.split('-');
    let year = parseInt(eventDateParts[0]);
    let month = parseInt(eventDateParts[1]);
    let day = parseInt(eventDateParts[2]);

    // Check if summary exists and adds days
    if (catalyst.summary && typeof catalyst.summary.daysSinceCatalystEvent === 'number') {
      let baseDate = new Date(year, month - 1, day);
      baseDate.setDate(baseDate.getDate() + catalyst.summary.daysSinceCatalystEvent);
      year = baseDate.getFullYear();
      month = baseDate.getMonth() + 1;
      day = baseDate.getDate();
    }
    dateToFormat = { year, month, day };
  }
}

// Fallback to current round's start date if no catalyst date is determined
if (!dateToFormat) {
  const round = gameData.rounds[String(currentRound)];
  if (round && round.startDate) {
    dateToFormat = round.startDate;
  }
}

if (dateToFormat) {
  return getFormattedDate(dateToFormat.year, dateToFormat.month, dateToFormat.day);
}

return 'Unknown Date';

const currentRoundData = gameData.rounds[String(currentRound)];
  if (!currentRoundData) {
    return "";
  }

  const russiaCountryData = Object.values(currentRoundData.countryDescriptions).find(country =>
    country.additionalNames && (
      country.additionalNames.includes('Russia') ||
      country.additionalNames.includes('Russian Empire') ||
      country.additionalNames.includes('Soviet Union') ||
      country.additionalNames.includes('USSR')
    )
  );

  if (!russiaCountryData) {
    return "";
  }

  const russianRegions = new Set(russiaCountryData.regionsOwned);
  const allRegions = gameData.regionNames;

  const isOceanOrStrait = (regionId) => {
    const regionDescription = mapGeometry.geometry[regionId];
    return regionDescription && (regionDescription.type === "Ocean" || regionDescription.type === "Strait");
  };

  const firstLayerBorderingRegions = new Set();
  const potentialSecondLayerRegions = new Set();

  // Identify first layer bordering regions (bordering non-Russian or ocean/strait regions)
  for (const regionId of russianRegions) {
    const adjacencies = mapGeometry.geometry[regionId]?.adjacencies || [];
    for (const adjId of adjacencies) {
      if (!russianRegions.has(adjId) || isOceanOrStrait(adjId)) {
        firstLayerBorderingRegions.add(regionId);
        break;
      }
    }
  }

  // Identify potential second layer regions (bordering first layer regions)
  for (const firstLayerRegionId of firstLayerBorderingRegions) {
    const adjacencies = mapGeometry.geometry[firstLayerRegionId]?.adjacencies || [];
    for (const adjId of adjacencies) {
      if (russianRegions.has(adjId) && !firstLayerBorderingRegions.has(adjId)) {
        potentialSecondLayerRegions.add(adjId);
      }
    }
  }

  const secondLayerRegionsNames = Array.from(potentialSecondLayerRegions)
    .map(regionId => allRegions[regionId])
    .filter(name => name)
    .sort();

  return secondLayerRegionsNames.join(', ');

const allChatsOutput = [];
const playerCountry = gameData.playerCountry;

const sortedRoundNumbers = Object.keys(gameData.rounds).map(Number).sort((a, b) => a - b);

const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];
const getOrdinalSuffix = (day) => {
    if (day > 3 && day < 21) return 'th';
    switch (day % 10) {
        case 1: return "st";
        case 2: return "nd";
        case 3: return "rd";
        default: return "th";
    }
};

for (const roundNum of sortedRoundNumbers) {
  const round = gameData.rounds[String(roundNum)];
  if (round && round.chats) {
    const startDate = round.startDate;
    const year = startDate.year;
    const month = monthNames[startDate.month - 1]; // months are 1-indexed in DateStructure
    const day = `${startDate.day}${getOrdinalSuffix(startDate.day)}`;
    const dateDescription = `on Round ${roundNum}, ${month} ${day}, ${year}`;

    for (const chatID in round.chats) {
      const chat = round.chats[chatID];
      if (chat.participants && chat.participants.includes(playerCountry)) {
        let participantStr = '';
        if (chat.participants.length > 2) {
          participantStr = chat.participants.slice(0, -1).join(', ') + ', and ' + chat.participants[chat.participants.length - 1];
        } else if (chat.participants.length === 2) {
          participantStr = chat.participants.join(' and ');
        } else if (chat.participants.length === 1) {
          participantStr = chat.participants[0];
        }

        let currentChatBlock = `A Chat between ${participantStr} ${dateDescription}:
`;
        if (chat.messages) {
          Object.values(chat.messages).forEach(msg => {
            currentChatBlock += `${msg.senderName}: "${msg.message}"
`;
          });
        }
        currentChatBlock += "END";
        allChatsOutput.push(currentChatBlock);
      }
    }
  }
}

return allChatsOutput.join("\n\n");

const allPlayerActions = []; for (const roundNumberStr in gameData.rounds) { const roundNumber = Number(roundNumberStr); if (roundNumber < currentRound) { const round = gameData.rounds[roundNumberStr]; if (round && round.actionsByPlayer) { for (const action of round.actionsByPlayer) { let actionDatePart = ''; if (action.date) { actionDatePart = `Action Date: ${action.date}`;} let actionDescriptionPart = ''; if (action.title && action.description && action.title !== action.description) { actionDescriptionPart = `${action.title}: ${action.description}`;} else if (action.title) { actionDescriptionPart = action.title;} else if (action.description) { actionDescriptionPart = action.description;} if (actionDatePart || actionDescriptionPart) { allPlayerActions.push(`${actionDatePart}
${actionDescriptionPart}`);}}}}} if (allPlayerActions.length === 0) { return 'No player actions recorded from previous rounds.';} return allPlayerActions.join('

');

const events = [];
const startRound = optionalData.consolidationStartRound;
const endRound = optionalData.consolidationEndRound;

if (startRound === undefined || endRound === undefined) {
    return "";
}

const monthNames = ["", "January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

for (let i = startRound; i <= endRound; i++) {
    const round = gameData.rounds[String(i)];
    if (!round) {
        continue; 
    }

    const roundEvents = [...round.actionsByPlayer, ...round.eventsBetweenStartDateAndEndDate];

    for (const event of roundEvents) {
        const dateString = event.date;
        const parts = dateString.split('-');
        const year = parseInt(parts[0]);
        const month = parseInt(parts[1]);
        const day = parseInt(parts[2].split(' ')[0]);
        const label = dateString.includes(' BC') ? 'BC' : '';

        const monthName = monthNames[month];

        let daySuffix;
        if (day >= 11 && day <= 13) {
            daySuffix = 'th';
        } else {
            switch (day % 10) {
                case 1: daySuffix = 'st'; break;
                case 2: daySuffix = 'nd'; break;
                case 3: daySuffix = 'rd'; break;
                default: daySuffix = 'th';
            }
        }
        const formattedDay = day + daySuffix;

        let formattedDate = `${monthName} ${formattedDay}, ${year}`;
        if (label === 'BC') {
            formattedDate += ' BC';
        }

        events.push(`${formattedDate}: ${event.description}`);
    }
}

return events.join('\n');

const playerCountry = gameData.playerCountry;
const output = [];

// Determine which rounds are consolidated by checking existing eventConsolidations
const consolidatedRounds = new Set();
if (gameData.eventConsolidations) {
  for (const consolidationID in gameData.eventConsolidations) {
    const consolidation = gameData.eventConsolidations[consolidationID];
    for (let r = consolidation.consolidationStartRound; r <= consolidation.consolidationEndRound; r++) {
      consolidatedRounds.add(r);
    }
  }
}

let foundAnyChats = false;

// Loop through rounds from 1 up to the currentRound
for (let i = 1; i <= currentRound; i++) {
  const roundNum = String(i);
  const roundData = gameData.rounds[roundNum];

  if (!roundData) {
    continue; // Skip if round data doesn’t exist
  }

  // Process chats only if this round has NOT been consolidated
  if (!consolidatedRounds.has(i)) {
    const chatsInRound = [];
    for (const chatID in roundData.chats) {
      const chat = roundData.chats[chatID];
      // Check if the player country is a participant in the chat
      if (chat.participants.includes(playerCountry)) {
        chatsInRound.push(chat);
      }
    }

    if (chatsInRound.length > 0) {
      foundAnyChats = true;
      output.push(`On round ${i}`);

      // Format the date for the current round
      const startDate = roundData.startDate;
      let formattedDate = '';
      if (startDate) {
        const year = startDate.year;
        const month = String(startDate.month).padStart(2, '0');
        const day = String(startDate.day).padStart(2, '0');
        formattedDate = `${year}-${month}-${day}`;
        if (startDate.label) {
          formattedDate += ` ${startDate.label}`;
        }
      }

      let isFirstChatInRound = true;
      for (const chat of chatsInRound) {
        // Add a blank line between multiple chats in the same round, if not the very first chat
        if (!isFirstChatInRound) {
          output.push('');
        }
        isFirstChatInRound = false;

        // Format participants list with 'and'
        let participantList = '';
        if (chat.participants.length === 1) {
          participantList = chat.participants[0];
        } else if (chat.participants.length === 2) {
          participantList = `${chat.participants[0]} and ${chat.participants[1]}`;
        } else if (chat.participants.length > 2) {
          participantList = chat.participants.slice(0, -1).join(', ') + `, and ${chat.participants[chat.participants.length - 1]}`;
        }

        let chatHeader = `A Chat between ${participantList}`;
        if (formattedDate) {
          chatHeader += ` on the date of ${formattedDate}`;
        }
        chatHeader += ':';
        output.push(chatHeader);

        for (const messageID in chat.messages) {
          const message = chat.messages[messageID];
          output.push(`${message.senderName}: "${message.message}"`);
        }
      }
      // Add two blank lines after all chats in a round, to separate from the next round header
      output.push('');
      output.push('');
    }
  }
}

if (!foundAnyChats) {
  return "No chats occurred in these rounds.";
}

// Join all parts with a single newline, handling the empty strings for spacing
return output.join('\n');

const currentRoundData = gameData.rounds[String(currentRound)];
if (!currentRoundData) {
    return "No game data available for the current round.";
}

const countryDescriptions = currentRoundData.countryDescriptions;
const mapFeatures = currentRoundData.mapFeatures || {};
const regionNames = gameData.regionNames;

if (!countryDescriptions) {
    return "No country descriptions found for the current round.";
}

const allCountryNames = Object.keys(countryDescriptions);
const majorCountryNames = [];
const otherCountryNames = [];

const countryDataMap = {};

for (const countryName of allCountryNames) {
    const description = countryDescriptions[countryName];
    const ownedRegions = description.regionsOwned || [];

    const battalions = [];
    const cities = [];

    for (const featureID in mapFeatures) {
        const feature = mapFeatures[featureID];
        if (feature.ownerName === countryName) {
            if (feature.tags && feature.tags.includes("battalion")) {
                const regionName = regionNames[feature.location?.regionID] || feature.location?.regionID;
                battalions.push(`"${feature.name}" Stationed in the Region of "${regionName}"`);
            }
            if (feature.tags && feature.tags.includes("city")) {
                cities.push(`“${feature.name}”`);
            }
        }
    }

    countryDataMap[countryName] = {
        regions: ownedRegions.map(regionID => `"${regionNames[regionID] || regionID}"`),
        battalions: battalions,
        cities: cities
    };

    if (ownedRegions.length > 12) {
        majorCountryNames.push(countryName);
    } else {
        otherCountryNames.push(countryName);
    }
}

majorCountryNames.sort((a, b) => a.localeCompare(b));
otherCountryNames.sort((a, b) => a.localeCompare(b));

const sortedCountryNames = [...majorCountryNames, ...otherCountryNames];
let output = [];

for (const countryName of sortedCountryNames) {
    const data = countryDataMap[countryName];
    output.push(`"${countryName}":`);
    output.push(`All Owned Regions:`);
    output.push(data.regions.join(", "));

    output.push(`All Battalions:`);
    output.push(data.battalions.length > 0 ? data.battalions.join("\n") : `No Major Battalions Listed for "${countryName}"`);

    output.push(`All Cities:`);
    output.push(data.cities.length > 0 ? data.cities.join(", ") : `No Major Cities Listed for "${countryName}"`);
    output.push(""); 
}

return output.join("\n").trim();

const currentRoundData = gameData.rounds[String(currentRound)];
if (!currentRoundData?.mapFeatures) return "";
const cityNames = [];
for (const featureID in currentRoundData.mapFeatures) {
  const feature = currentRoundData.mapFeatures[featureID];
  if (feature.tags && feature.tags.includes("city")) {
    cityNames.push(feature.name);
  }
}
cityNames.sort();
return cityNames.join(", ");

if (!optionalData || !optionalData.previousStageResultRoundData) {
  return "Error: Missing previous stage map data. This helper needs 'optionalData.previousStageResultRoundData' to compare ownership changes.";
}

const previousRoundData = optionalData.previousStageResultRoundData;
const currentRoundState = gameData.rounds[String(currentRound)];

if (!currentRoundState) {
  return "Error: Current round game data is not available. Ensure 'gameData.rounds[currentRound]' exists.";
}

// Helper to get a map of regionID to ownerName
const getRegionOwnershipMap = (roundState) => {
  const ownership = new Map();
  if (!roundState || !roundState.countryDescriptions) {
    return ownership;
  }
  for (const countryName in roundState.countryDescriptions) {
    const country = roundState.countryDescriptions[countryName];
    if (Array.isArray(country.regionsOwned)) {
      for (const regionId of country.regionsOwned) {
        // Ensure regionId is a valid string
        if (typeof regionId === 'string' && regionId.length > 0) {
          ownership.set(regionId, countryName);
        }
      }
    }
  }
  return ownership;
};

const previousRegionOwners = getRegionOwnershipMap(previousRoundData);
const currentRegionOwners = getRegionOwnershipMap(currentRoundState);

// Helper to find all contiguous regions owned by the same country (an 'island')
// Returns a Set of region IDs. Takes a 'visited' set to avoid infinite loops in graph traversal
const getContiguousIsland = (startRegionID, ownerName, ownershipMap, mapGeo, visited) => {
  const island = new Set();
  const queue = [startRegionID];
  let head = 0;

  // Basic validation
  if (!mapGeo || !mapGeo.geometry || !ownershipMap || !ownershipMap.has(startRegionID) || ownershipMap.get(startRegionID) !== ownerName) {
    return island; // Not a valid starting point for an island owned by this owner
  }

  while (head < queue.length) {
    const currentRegionID = queue[head++];

    if (visited.has(currentRegionID)) {
      continue;
    }
    visited.add(currentRegionID);
    island.add(currentRegionID);

    const regionGeo = mapGeo.geometry[currentRegionID];
    if (regionGeo && Array.isArray(regionGeo.adjacencies)) {
      for (const adjID of regionGeo.adjacencies) {
        if (typeof adjID === 'string' && adjID.length > 0 && ownershipMap.get(adjID) === ownerName && !visited.has(adjID)) {
          queue.push(adjID);
        }
      }
    }
  }
  return island;
};

const allRegionIDsInMap = Object.keys(gameData.regionData || {});
const newlyEncircledIslands = []; // Stores { regions: Set<string>, owner: string }
const processedIslandRegionsTracker = new Set(); // To avoid processing the same island multiple times

// --- Part 1: Regions NOT involved in transfers, whose island size dropped significantly --- 
const regionsNotTransferred = new Set();
for (const regionID of allRegionIDsInMap) {
  const prevOwner = previousRegionOwners.has(regionID) ? previousRegionOwners.get(regionID) : "unowned";
  const currentOwner = currentRegionOwners.has(regionID) ? currentRegionOwners.get(regionID) : "unowned";

  if (prevOwner === currentOwner && prevOwner !== "unowned") {
    regionsNotTransferred.add(regionID);
  }
}

for (const regionID of regionsNotTransferred) {
  if (processedIslandRegionsTracker.has(regionID)) continue;

  const currentOwner = currentRegionOwners.get(regionID);
  if (currentOwner === "unowned") continue; // Should not happen for this part due to above filter, but defensive.

  const visitedForPreviousIsland = new Set();
  const previousIsland = getContiguousIsland(regionID, currentOwner, previousRegionOwners, mapGeometry, visitedForPreviousIsland);

  const visitedForCurrentIsland = new Set();
  const currentIsland = getContiguousIsland(regionID, currentOwner, currentRegionOwners, mapGeometry, visitedForCurrentIsland);

  if (previousIsland.size > 0 && currentIsland.size > 0 && currentIsland.size < 0.5 * previousIsland.size) {
    // Check if this specific island (currentIsland) has already been captured
    let isDuplicateIsland = false;
    for(const existingIslandData of newlyEncircledIslands) {
      if (existingIslandData.regions.size === currentIsland.size) {
        // Simple size check as a quick filter, then deep check
        const intersection = new Set([...existingIslandData.regions].filter(x => currentIsland.has(x)));
        if (intersection.size === existingIslandData.regions.size) { // Means they are the same set of regions
          isDuplicateIsland = true;
          break;
        }
      }
    }

    if (!isDuplicateIsland) {
      newlyEncircledIslands.push({ regions: currentIsland, owner: currentOwner });
      currentIsland.forEach(rID => processedIslandRegionsTracker.add(rID));
    }
  }
}

// --- Part 2: Regions that *were* part of ownership transfers, and now don't touch same-owner regions ---
for (const regionID of allRegionIDsInMap) {
  const prevOwner = previousRegionOwners.has(regionID) ? previousRegionOwners.get(regionID) : "unowned";
  const currentOwner = currentRegionOwners.has(regionID) ? currentRegionOwners.get(regionID) : "unowned";

  // Only process regions that changed ownership AND are now owned (not unowned)
  if (prevOwner !== currentOwner && currentOwner !== "unowned") {
    // Check if this region is already part of an island from Part 1 calculation (should have been added to tracker)
    if (processedIslandRegionsTracker.has(regionID)) continue; 

    let hasSameOwnerNeighbor = false;
    const regionGeo = mapGeometry.geometry[regionID];
    if (regionGeo && Array.isArray(regionGeo.adjacencies)) {
      for (const adjID of regionGeo.adjacencies) {
        if (typeof adjID === 'string' && adjID.length > 0 && currentRegionOwners.get(adjID) === currentOwner) {
          hasSameOwnerNeighbor = true;
          break;
        }
      }
    }

    if (!hasSameOwnerNeighbor) {
      const newSingleRegionIsland = new Set([regionID]);
      newlyEncircledIslands.push({ regions: newSingleRegionIsland, owner: currentOwner });
      processedIslandRegionsTracker.add(regionID); // Mark as processed
    }
  }
}

if (newlyEncircledIslands.length === 0) {
  return "No newly created encirclements detected in this round based on definition.";
}

const resultSentences = [];

for (const islandData of newlyEncircledIslands) {
  const islandOwner = islandData.owner;
  const islandRegionNames = Array.from(islandData.regions)
    .map(rID => gameData.regionData?.[rID]?.name || rID) // Fallback to ID if name missing
    .sort();

  const borderingEntities = new Set();
