const output = [];

const formatDate = (dateStruct) => {
    if (!dateStruct || typeof dateStruct.year === 'undefined' || typeof dateStruct.month === 'undefined' || typeof dateStruct.day === 'undefined') {
        return "Unknown Date";
    }
    const year = String(dateStruct.year);
    const month = String(dateStruct.month).padStart(2, '0');
    const day = String(dateStruct.day).padStart(2, '0');
    const label = dateStruct.label ? ` ${dateStruct.label}` : '';
    return `${year}-${month}-${day}${label}`;
};

// Helper to get a sortable epoch from a date string or DateStructure
const getEpoch = (dateInput) => {
    if (!dateInput) return 0;
    let dateString;
    if (typeof dateInput === 'string') {
        dateString = dateInput;
    } else if (typeof dateInput === 'object' && dateInput.year) {
        dateString = formatDate(dateInput);
    } else {
        return 0;
    }
    // Remove AD/BC labels for Date constructor compatibility
    return new Date(dateString.replace(/ AD| BC/g, '')).getTime();
};

// --- 1. Process Consolidations --- //
const consolidations = Object.values(gameData.eventConsolidations || {}).sort((a, b) => {
    return (a.consolidationStartRound - b.consolidationStartRound);
});

let maxConsolidatedRound = 0;
for (const consolidation of consolidations) {
    maxConsolidatedRound = Math.max(maxConsolidatedRound, consolidation.consolidationEndRound);

    const startRoundNum = consolidation.consolidationStartRound;
    const endRoundNum = consolidation.consolidationEndRound;

    const startRoundData = gameData.rounds[String(startRoundNum)];
    const nextRoundData = gameData.rounds[String(endRoundNum + 1)];

    // Start date of the consolidation is the start date of the first round in the consolidation
    const startDate = startRoundData?.startDate;
    // End date of the consolidation is the start date of the round *after* the consolidated range
    let consolidationEndDate = nextRoundData?.startDate;

    let consolidationHeader = `Consolidation for Rounds ${startRoundNum}-${endRoundNum}`;
    if (startDate && consolidationEndDate) {
        consolidationHeader += ` (From ${formatDate(startDate)} to ${formatDate(consolidationEndDate)})`;
    } else if (startDate) {
        // If there's no next round, it implies consolidation to the present or end of game state
        consolidationHeader += ` (From ${formatDate(startDate)} to present)`;
    }

    let fullConsolidationText = consolidation.consolidationString;

    // Append catalyst summaries for rounds within this consolidated range
    let consolidatedCatalystSummaries = [];
    for (let r = startRoundNum; r <= endRoundNum; r++) {
        const round = gameData.rounds[String(r)];
        if (round && round.catalysts) {
            for (const catalystID in round.catalysts) {
                const catalyst = round.catalysts[catalystID];
                if (catalyst.summary?.summaryString) {
                    consolidatedCatalystSummaries.push(`- Catalyst Summary (Round ${r}): ${catalyst.summary.summaryString}`);
                }
            }
        }
    }
    output.push(`${consolidationHeader}\n${fullConsolidationText}`);
}

// --- 2. Process Unconsolidated Events and Catalysts --- //
const firstUnconsolidatedRound = maxConsolidatedRound + 1;
const allUnconsolidatedEntries = [];

// Helper to add structured entries
const addEntry = (type, date, data) => {
    allUnconsolidatedEntries.push({
        type: type,
        date: date,
        data: data,
        eventEpoch: getEpoch(date)
    });
};

for (let r = firstUnconsolidatedRound; r <= currentRound; r++) {
    const round = gameData.rounds[String(r)];
    if (!round) continue;

    const roundStartDate = round.startDate;

    // Add eventsBetweenStartDateAndEndDate
    if (round.eventsBetweenStartDateAndEndDate) {
        for (const event of round.eventsBetweenStartDateAndEndDate) {
            addEntry('event', event.date, event);
        }
    }
    // Add actionsByPlayer
    if (round.actionsByPlayer) {
        for (const action of round.actionsByPlayer) {
            addEntry('event', action.date, action);
        }
    }

    // Add completed catalyst summaries for the current round
    if (round.catalysts) {
        for (const catalystID in round.catalysts) {
            const catalyst = round.catalysts[catalystID];
            if (catalyst.summary?.summaryString) {
                // If catalystEvent exists, use its date. Otherwise, use the round's start date.
                // The 'catalystEvent' field is deprecated for engine use but may exist for display.
                const catalystDate = catalyst.catalystEvent?.date || formatDate(roundStartDate);
                addEntry('catalystSummary', catalystDate, { summary: catalyst.summary.summaryString, id: catalystID });
            }
        }
    }
}

// Sort all gathered unconsolidated entries chronologically
allUnconsolidatedEntries.sort((a, b) => a.eventEpoch - b.eventEpoch);

for (const entry of allUnconsolidatedEntries) {
    let entryTextLines = [];
    if (entry.type === 'event') {
        const event = entry.data;
        entryTextLines.push(`${event.date}`);
        if (event.title) {
            entryTextLines.push(`Title: ${event.title}`);
        }
        if (event.sourceCountry) {
            entryTextLines.push(`Source: ${event.sourceCountry}`);
        }
        entryTextLines.push(`Description: ${event.description}`);
    } else if (entry.type === 'catalystSummary') {
        entryTextLines.push(`${entry.date}`);
        entryTextLines.push(`An event was simulated in far more detail as of this date, Here is the summary of what happened in that event: ${entry.data.summary}`);
    }
    output.push(entryTextLines.join('\n'));
}

return output.filter(Boolean).join('\n\n');

