            if (decision && typeof decision === 'object' && 'selectedOptionID' in decision && decision.selectedOptionID !== null && decision.options && decision.options[decision.selectedOptionID]) {
                const selectedOption = decision.options[decision.selectedOptionID];
                const selectedOptionText = selectedOption.text;
                const selectedOptionConsequences = selectedOption.consequences;

                let baseDescription = `On ${roundDate}, on the specific decision of \"${decision.title}\", with the explanation: \"${decision.explaination}\", the player made the decision to \"${selectedOptionText}\"`;
                let consequenceString = '';

                if (selectedOptionConsequences && selectedOptionConsequences.trim() !== '') {
                    consequenceString = `. Consider the planned consequences, which may or may not be realistic: ${selectedOptionConsequences}.`;
                }

                const decisionDescription = `${baseDescription}${consequenceString || '.'}`;

                if (roundNum < currentRound) {
                    treeDecisionsInPast.push(decisionDescription);
                } else if (roundNum === currentRound) {
                    treeDecisionsInCurrentRound.push(decisionDescription);
                }
