    let treeReport = completionPrefix;
    treeReport += `As part of the objective '\"${tree.title}\": ${tree.description}'`;

    const hasPastDecisions = treeDecisionsInPast.length > 0;
    const hasCurrentDecisions = treeDecisionsInCurrentRound.length > 0;

    if (hasPastDecisions) {
        treeReport += `, previously the player: ${treeDecisionsInPast.join('; ')}`;
    }

    if (hasCurrentDecisions) {
        if (hasPastDecisions) {
