        const dateA_sort = parseEventDateForSort(a.date, roundStartDate);
        const dateB_sort = parseEventDateForSort(b.date, roundStartDate);
        return dateA_sort - dateB_sort;
    });

    for (const event of roundEvents) {
        const eventTitle = event.title || "";
        const eventDescription = event.description || "";
        const eventMapUpdates = formatMapChanges(event.mapChanges, gameData.regionData);

        const eventDisplayDate = event.date || formatDate(roundStartDate);

        let entryText = `Event Title and Date: "${eventTitle}" on ${eventDisplayDate}\nDescription: "${eventDescription}"`;
        if (eventMapUpdates) {
            entryText += `\nMap Updates: "${eventMapUpdates}"`;
        }

        const entrySortKey = parseEventDateForSort(event.date, roundStartDate);
        allEntries.push({ sortKey: entrySortKey, displayString: entryText });
    }
}

// 3. Sort all collected entries (consolidations and individual events) chronologically
allEntries.sort((a, b) => a.sortKey - b.sortKey);

