  for (const consolidationId in gameData.eventConsolidations) {
    const consolidation = gameData.eventConsolidations[consolidationId];
    if (consolidation && typeof consolidation.consolidationStartRound === 'number') {
      consolidationsMap[consolidation.consolidationStartRound] = consolidation;
    }
  }
}

for (let roundNum = 1; roundNum < maxRound; roundNum++) {
  if (processedRounds.has(roundNum)) {
    continue;
  }

  // Check if this round starts a consolidation that ends before the current round
  const consolidation = consolidationsMap[roundNum];
  if (consolidation && consolidation.consolidationEndRound < maxRound) {
    result.push(`--- Historical Consolidation (Rounds ${consolidation.consolidationStartRound}-${consolidation.consolidationEndRound}) ---`);
    result.push(consolidation.consolidationString);
    for (let r = consolidation.consolidationStartRound; r <= consolidation.consolidationEndRound; r++) {
      processedRounds.add(r);
    }
    // Jump the loop counter past the consolidated rounds
    roundNum = consolidation.consolidationEndRound;
    continue; 
  }

  // Process individual events for the round if not covered by a consolidation
  const roundData = gameData.rounds[String(roundNum)];
  if (!roundData) {
    continue; // Skip if round data is missing
  }

  result.push(`--- Round ${roundNum} (Starts: ${formatDate(roundData.startDate)}) ---`);

  const allEventsInRound = [
    ...(roundData.actionsByPlayer || []),
    ...(roundData.eventsBetweenStartDateAndEndDate || [])
  ];

  if (allEventsInRound.length === 0) {
    result.push("  (No events recorded for this round)");
  } else {
    for (const event of allEventsInRound) {
      if (!event || typeof event.description !== 'string') continue; // Skip malformed events

      let eventStr = `  ${event.date}`;
      if (typeof event.sourceCountry === 'string' && event.sourceCountry.length > 0) {
        eventStr += ` (${event.sourceCountry})`;
      }
      if (typeof event.title === 'string' && event.title.length > 0) {
        eventStr += `: ${event.title}`;
      }
      eventStr += ` - ${event.description}`;
      result.push(eventStr);
    }
  }
}

return result.join('\n');

