    // 1. Determine First Layer Bordering Regions
    for (const regionId of ownedRegionsSet) {
        const adjacencies = mapGeometry.geometry[regionId]?.adjacencies || [];
        let isFirstLayer = false;
        for (const adjRegionId of adjacencies) {
            // Check if bordering a foreign nation
            if (allRegionOwners[adjRegionId] && allRegionOwners[adjRegionId] !== countryName) {
                isFirstLayer = true;
                break;
            }
            // Check if bordering an Ocean or Strait type region
            const adjRegionType = mapGeometry.geometry[adjRegionId]?.type;
            if (adjRegionType === "Ocean" || adjRegionType === "Strait") {
                isFirstLayer = true;
                break;
