        }
        if (isFirstLayer) {
            firstLayerRegionIDs.add(regionId);
        }
    }

    // 2. Determine Second Layer Bordering Regions
    for (const regionId of ownedRegionsSet) {
        if (!firstLayerRegionIDs.has(regionId)) { // Must not already be a first layer region
            const adjacencies = mapGeometry.geometry[regionId]?.adjacencies || [];
            let isSecondLayer = false;
