    .filter(regionId => chineseRegionsOwned.has(regionId)) // Ensure only Chinese regions are included
    .map(regionId => gameData.regionNames[regionId] || regionId)
    .sort((a, b) => a.localeCompare(b));

return resultRegionNames.join(', ');

const chatID = optionalData.chatID; if (!chatID) { return ''; } 
const currentChat = gameData.rounds[String(currentRound)]?.chats?.[chatID]; if (!currentChat) { return ''; } 
const lastMessageIndex = Object.keys(currentChat.messages).length - 1; if (lastMessageIndex < 0) { return ''; } return optionalData.respondingCountryName || '';

const targetRoundNumber = currentRound + 1;
const r = gameData.rounds[String(targetRoundNumber)];
const d = r?.startDate;

if (!d) return 'Undated';

const year = d.year;
const day = d.day;
const monthNames = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];
const monthName = d.month ? monthNames[d.month - 1] : 'Unknown Month';

const getOrdinalSuffix = (n) => {
  if (n > 3 && n < 21) return 'th';
  switch (n % 10) {
    case 1: return 'st';
    case 2: return 'nd';
    case 3: return 'rd';
    default: return 'th';
  }
};

const formattedDay = day ? `${day}${getOrdinalSuffix(day)}` : '';
const formattedLabel = d.label ? ` ${d.label}` : '';

// Construct the grammatical date string
let dateString = '';
if (monthName !== 'Unknown Month' && monthName !== undefined) {
  dateString += `${monthName} `;
}
if (formattedDay) {
  dateString += `${formattedDay}, `;
}
if (year) {
  dateString += `${year}`;
}

return `${dateString}${formattedLabel}`.trim();

try {
    const validatedResponseToGrade = optionalData.validatedResponseToGrade;
    let eventsToGrade = [];

    if (validatedResponseToGrade) {
        try {
            const parsed = JSON.parse(validatedResponseToGrade);
            // Check for 'events' array structure, as validated responses usually consolidate into this.
            // also keep the 'chat' for backward compatibility or specific prompt types.
            if (parsed && Array.isArray(parsed.events)) {
                eventsToGrade = parsed.events;
            } else if (parsed && Array.isArray(parsed.chat)) { // Sometimes 'chat' directly contains events in tests or specific prompt outputs
                eventsToGrade = parsed.chat;
            }
        } catch (e) {
            // JSON parsing failed, eventsToGrade remains empty
            return `Error parsing validated response: ${e.message}`;
        }
    }

    const currentRoundData = gameData.rounds[String(currentRound)];
    const countryDescriptions = currentRoundData?.countryDescriptions || {};

    const getPolityDisplayName = (polityId) => {
        if (polityId === null) return "Unowned"; // Specifically for toPolity: null
        const country = countryDescriptions[polityId];
        if (country) {
            if (country.additionalNames && country.additionalNames.length > 0) {
                // Return the first additional name, and append the primary name (ID) in parentheses for clarity
                return `${country.additionalNames[0]} (${polityId})`;
            }
            return polityId; // No additional names, use the ID (which is also the primary name)
        }
        return `Unknown Polity (${polityId})`; // Polity ID not found in descriptions, but still show it.
    };

    const formatMapChange = (change) => {
        switch (change.type) {
            case "createPolity":
                return `- Create Polity: "${getPolityDisplayName(change.polity.name)}" (Color: ${change.polity.color||'N/A'})`;
            case "transferRegionOwnership":
                const transfers = change.transfers.map(t => {
                    const regionNames = t.regionIDs.map(id => gameData.regionData[id]?.name || id).join(', ');
                    return `  - Regions [${regionNames}] to "${getPolityDisplayName(t.toPolity)}"`;
                }).join('\n');
                return `- Transfer Region Ownership:\n${transfers}`;
            case "dissolvePolity":
                return `- Dissolve Polity: "${getPolityDisplayName(change.polityName)}"`;
            case "updatePolity":
                let updateDetails = [`- Update Polity: "${getPolityDisplayName(change.name)}"`];
                if (change.newName) updateDetails.push(`  - New Name: "${getPolityDisplayName(change.newName)}"`);
                if (change.color) updateDetails.push(`  - New Color: ${change.color}`);
                if (change.setAdditionalNamesTo) updateDetails.push(`  - Set Additional Names to: [${change.setAdditionalNamesTo.join(', ')}]`);
                return updateDetails.join('\n');
            case "createMapFeature":
                const featureLocation = change.feature.type === 'centroid' ? `Region: ${gameData.regionData[change.feature.location.regionID]?.name || change.feature.location.regionID}` : `Coords: ${change.feature.location.longitude}, ${change.feature.location.latitude}`;
                return `- Create Map Feature: "${change.feature.name}" (Type: ${change.feature.type}, Owner: "${getPolityDisplayName(change.feature.ownerName || '')}", Location: ${featureLocation})`;
            case "updateMapFeature":
                let featureUpdateDetails = [`- Update Map Feature: "${change.name}"`];
                if (change.properties.name) featureUpdateDetails.push(`  - New Name: "${change.properties.name}"`);
                if (change.properties.ownerName) featureUpdateDetails.push(`  - New Owner: "${getPolityDisplayName(change.properties.ownerName || '')}"`);
                if (change.properties.location) {
                   const newLocation = change.properties.type === 'centroid' ? `New Region: ${gameData.regionData[change.properties.location.regionID]?.name || change.properties.location.regionID}` : `New Coords: ${change.properties.location.longitude}, ${change.properties.location.latitude}`;
                   featureUpdateDetails.push(`  - ${newLocation}`);
                }
                return featureUpdateDetails.join('\n');
            case "removeMapFeature":
                return `- Remove Map Feature: "${change.name}"`;
            default:
                return `- Unhandled Map Change Type: ${change.type} - ${JSON.stringify(change)}`;
        }
    };

    const formattedEvents = eventsToGrade.map((event, index) => {
        let eventString = `Event ID: event_${index + 1}`;
        if (event.title) {
            eventString += `\nTitle: ${event.title}`;
        }
        eventString += `\nDescription: ${event.description || 'No description provided.'}`;
        if (event.mapChanges && event.mapChanges.length > 0) {
            eventString += `\nMap Changes:\n${event.mapChanges.map(formatMapChange).join('\n')}`;
        }
        if (event.chat) {
            const chat = event.chat;
            eventString += `\nChat Invitation: Participants: ${chat.participants ? chat.participants.join(', ') : 'N/A'}, First Sender: ${chat.initialMessageSender || 'N/A'}, Message: ${chat.initialMessage || 'N/A'}`;
        }
        return eventString;
    }).join('\n\n');

    return formattedEvents || "No validated events found to grade.";
} catch (e) {
    return `Error in helper: ${e.message}`;
}

const formatDate = (dateObj) => {
  if (!dateObj) return '????-??-??';
  const y = dateObj.year ?? '????';
  const m = String(dateObj.month ?? '??').padStart(2, '0');
  const d = String(dateObj.day ?? '??').padStart(2, '0');
  return `${y}-${m}-${d}${dateObj.label ? ' ' + dateObj.label : ''}`;
};

const parseEventDateForSort = (dateString, fallbackDateStructure = null) => {
    let year, month, day, label;

    if (dateString && dateString !== "") {
        const parts = dateString.split('-');
        year = parseInt(parts[0].replace(' BC', '').replace(' AD', ''));
        month = parseInt(parts[1]);
        day = parseInt(parts[2].split(' ')[0]);
        label = dateString.includes(' BC') ? 'BC' : 'AD';
    } else if (fallbackDateStructure) {
        year = fallbackDateStructure.year;
        month = fallbackDateStructure.month;
        day = fallbackDateStructure.day;
        label = fallbackDateStructure.label;
    } else {
        return Number.MIN_SAFE_INTEGER; // Indicate an unsortable/invalid date
    }

    let sortYear = year;
    if (label === 'BC') {
        sortYear = -year; // Make BC years sort correctly before AD years, smaller magnitude = later in BC
    }

    return sortYear * 1000000 + month * 10000 + day * 100;
};

const formatMapChanges = (mapChanges, allRegionData) => {
    if (!Array.isArray(mapChanges) || mapChanges.length === 0) {
        return ""; // Return empty string if no map changes
    }
    const changes = [];
    for (const change of mapChanges) {
        switch (change.type) {
            case "createPolity":
                changes.push(`Created Polity: ${change.polity.name} (Color: ${change.polity.color})`);
                break;
            case "transferRegionOwnership":
                const transfers = change.transfers.map(t => {
                    const regionNames = t.regionIDs.map(id => allRegionData[id] ? `"${allRegionData[id].name}"` : `ID:"${id}"`).join(', ');
                    return `Region(s) of ${regionNames} was transferred to "${t.toPolity || 'unowned'}"`;
                }).join('; ');
                changes.push(transfers);
                break;
            case "dissolvePolity":
                changes.push(`Dissolved Polity: "${change.polityName}"`);
                break;
            case "updatePolity":
                let updateDetails = [`Updated Polity: ${change.name}`];
                if (change.newName) updateDetails.push(`New Name: ${change.newName}`);
                if (change.color) updateDetails.push(`New Color: ${change.color}`);
                if (change.setAdditionalNamesTo) updateDetails.push(`Additional Names Set To: [${change.setAdditionalNamesTo.join(', ')}]`);
                changes.push(updateDetails.join(', '));
                break;
            case "createMapFeature":
                // Only display if the new feature is a battalion
                if (change.feature.tags && change.feature.tags.includes('battalion')) {
                    changes.push(`Created Map Feature: "${change.feature.name}"`);
                }
                break;
            case "updateMapFeature":
                // Cannot reliably check feature tags before update within this scope.
                // User request implies checking current properties of the update.
                // Displaying update of a feature name, assuming it meets criterion if it has 'battalion' tag in its *new* properties.
                // If no tags specified in properties, we cannot determine its type from the update itself.
                // To align with the user's intent to show 'battalion' specific updates:
                if (change.properties && change.properties.tags && change.properties.tags.includes('battalion')) {
                    let updateText = `Updated Map Feature: "${change.name}"`;
                    if (change.properties.name && change.properties.name !== change.name) {
                        updateText += ` to "${change.properties.name}"`;
                    }
                    changes.push(updateText);
                }
                break;
            case "removeMapFeature":
                // The user's request for mapping feature changes applies to 'updated, what they became' and specifically mentions 'battalion' tags.
                // Determining if a *removed* feature was a battalion would require access to the map state *before* removal, which is not available in this function's current context without adding complex state tracking.
                // Therefore, 'removeMapFeature' is omitted from this filtered list as it doesn't fit the 'what they became' criteria or the 'battalion' check easily.
                break;
            default:
                changes.push(`(Unknown Map Change Type: ${change.type})`);
                break;
        }
    }
    return changes.join('; '); // Join multiple map changes with semicolon
};

let allEntries = [];
let processedConsolidationRounds = new Set();

// Gather and sort consolidations, ensuring they are valid objects
const rawConsolidations = Object.values(gameData.eventConsolidations || {}).filter(c => c && typeof c.consolidationStartRound === 'number' && typeof c.consolidationEndRound === 'number');
rawConsolidations.sort((a, b) => a.consolidationStartRound - b.consolidationStartRound);

// Loop through rounds up to currentRound
for (let i = 0; i <= currentRound; i++) {
  if (processedConsolidationRounds.has(i)) {
    continue; // This round is already covered by a processed consolidation
  }

  const round = gameData.rounds[String(i)];
  if (!round) {
    continue; // No data for this round
  }

  let consolidationAddedForThisRound = false;
  // Check if this round starts an unprocessed consolidation block
  for (const consolidation of rawConsolidations) {
    if (consolidation.consolidationStartRound === i && !processedConsolidationRounds.has(i)) {
      // Found a consolidation that starts at this round
      const startRoundData = gameData.rounds[String(consolidation.consolidationStartRound)];
      const endRoundData = gameData.rounds[String(consolidation.consolidationEndRound)]; // Get data for the last consolidated round

      const startDateFormat = startRoundData ? formatDate(startRoundData.startDate) : '????-??-??';
      // As per user request, the end date of the consolidation refers to the start date of the *last consolidated round*
      const endDateFormatForConsolidation = endRoundData ? formatDate(endRoundData.startDate) : '????-??-??'; 

      const consolidationDisplayString = `Summary of Events from ${startDateFormat} - ${endDateFormatForConsolidation}: "${consolidation.consolidationString}"`;
      const consolidationSortKey = parseEventDateForSort(startDateFormat, startRoundData?.startDate);

      allEntries.push({ sortKey: consolidationSortKey, displayString: consolidationDisplayString });

      // Mark all rounds in this consolidation range as processed
      for (let k = consolidation.consolidationStartRound; k <= consolidation.consolidationEndRound; k++) {
        processedConsolidationRounds.add(k);
      }
      // Adjust loop counter to skip to the end of the consolidated block
      i = consolidation.consolidationEndRound;
      consolidationAddedForThisRound = true;
      break; // Move to the next outer loop iteration after processing this consolidation
    }
  }

  // If no consolidation was added for this round, add its individual events
  if (!consolidationAddedForThisRound) {
    const roundStartDate = round.startDate;

    // Only include eventsBetweenStartDateAndEndDate for this round, and sort them by date before adding.
    const roundEvents = [...(round.eventsBetweenStartDateAndEndDate || [])];
    roundEvents.sort((a, b) => {
        const dateA_ms = new Date(a.date || formatDate(roundStartDate)).getTime();
        const dateB_ms = new Date(b.date || formatDate(roundStartDate)).getTime();
        return dateA_ms - dateB_ms;
    });

    for (const event of roundEvents) {
        const eventTitle = event.title || ""; // Ensure title is an empty string if null/undefined
        const eventDescription = event.description || ""; // Ensure description is an empty string if null/undefined
        const eventMapUpdates = formatMapChanges(event.mapChanges, gameData.regionData);

        // Determine the date to display for the event (using event.date string or formatting roundStartDate)
        const eventDisplayDate = event.date || formatDate(roundStartDate);

        // Update the entryText format to include the date with the title
        let entryText = `Event Title and Date: "${eventTitle}" on ${eventDisplayDate}\nDescription: "${eventDescription}"`;
        if (eventMapUpdates) {
            entryText += `\nMap Updates: "${eventMapUpdates}"`;
        }

        const entrySortKey = parseEventDateForSort(event.date, roundStartDate);
        allEntries.push({ sortKey: entrySortKey, displayString: entryText });
    }
  }
}

// Sort all entries chronologically
allEntries.sort((a, b) => a.sortKey - b.sortKey);

let result = '';
for (const entry of allEntries) {
  result += entry.displayString + '\n\n';
}

return result.trim();

const roundData = gameData.rounds[String(currentRound)];
if (!roundData) {
  return "Round data not found.";
}
const events = roundData.eventsBetweenStartDateAndEndDate;
if (!events || events.length === 0) {
  return "No events reported for this round.";
}
return events.map(event => event.description).join("\n");

if (!optionalData || !optionalData.previousStageResultRoundData) {
  return "Error: Missing previous stage map data. This helper needs 'optionalData.previousStageResultRoundData' to compare ownership changes.";
}

const previousRoundData = optionalData.previousStageResultRoundData;
const currentRoundState = gameData.rounds[String(currentRound)];

if (!currentRoundState) {
  return "Error: Current round game data is not available. Ensure 'gameData.rounds[currentRound]' exists.";
}

// Helper to get a map of regionID to ownerName
const getRegionOwnershipMap = (roundState) => {
  const ownership = new Map();
  if (!roundState || !roundState.countryDescriptions) {
    return ownership;
  }
  for (const countryName in roundState.countryDescriptions) {
    const country = roundState.countryDescriptions[countryName];
    if (Array.isArray(country.regionsOwned)) {
      for (const regionId of country.regionsOwned) {
        // Ensure regionId is a valid string
        if (typeof regionId === 'string' && regionId.length > 0) {
          ownership.set(regionId, countryName);
        }
      }
    }
  }
  return ownership;
};

const previousRegionOwners = getRegionOwnershipMap(previousRoundData);
const currentRegionOwners = getRegionOwnershipMap(currentRoundState);

// Helper to find all contiguous regions owned by the same country (an 'island')
// Returns a Set of region IDs. Takes a 'visited' set to avoid infinite loops in graph traversal
const getContiguousIsland = (startRegionID, ownerName, ownershipMap, mapGeo, visited) => {
  const island = new Set();
  const queue = [startRegionID];
  let head = 0;

  // Basic validation
  if (!mapGeo || !mapGeo.geometry || !ownershipMap || !ownershipMap.has(startRegionID) || ownershipMap.get(startRegionID) !== ownerName) {
    return island; // Not a valid starting point for an island owned by this owner
  }

  while (head < queue.length) {
    const currentRegionID = queue[head++];

    if (visited.has(currentRegionID)) {
      continue;
    }
    visited.add(currentRegionID);
    island.add(currentRegionID);

    const regionGeo = mapGeo.geometry[currentRegionID];
    if (regionGeo && Array.isArray(regionGeo.adjacencies)) {
      for (const adjID of regionGeo.adjacencies) {
        if (typeof adjID === 'string' && adjID.length > 0 && ownershipMap.get(adjID) === ownerName && !visited.has(adjID)) {
          queue.push(adjID);
        }
      }
    }
  }
  return island;
};

const allRegionIDsInMap = Object.keys(gameData.regionData || {});
const newlyEncircledIslands = []; // Stores { regions: Set<string>, owner: string }
const processedIslandRegionsTracker = new Set(); // To avoid processing the same island multiple times

// --- Part 1: Regions NOT involved in transfers, whose island size dropped significantly --- 
const regionsNotTransferred = new Set();
for (const regionID of allRegionIDsInMap) {
  const prevOwner = previousRegionOwners.has(regionID) ? previousRegionOwners.get(regionID) : "unowned";
  const currentOwner = currentRegionOwners.has(regionID) ? currentRegionOwners.get(regionID) : "unowned";

  if (prevOwner === currentOwner && prevOwner !== "unowned") {
    regionsNotTransferred.add(regionID);
  }
}

for (const regionID of regionsNotTransferred) {
  if (processedIslandRegionsTracker.has(regionID)) continue;

  const currentOwner = currentRegionOwners.get(regionID);
  if (currentOwner === "unowned") continue; // Should not happen for this part due to above filter, but defensive.

  const visitedForPreviousIsland = new Set();
  const previousIsland = getContiguousIsland(regionID, currentOwner, previousRegionOwners, mapGeometry, visitedForPreviousIsland);

  const visitedForCurrentIsland = new Set();
  const currentIsland = getContiguousIsland(regionID, currentOwner, currentRegionOwners, mapGeometry, visitedForCurrentIsland);

  if (previousIsland.size > 0 && currentIsland.size > 0 && currentIsland.size < 0.5 * previousIsland.size) {
    // Check if this specific island (currentIsland) has already been captured
    let isDuplicateIsland = false;
    for(const existingIslandData of newlyEncircledIslands) {
      if (existingIslandData.regions.size === currentIsland.size) {
        // Simple size check as a quick filter, then deep check
        const intersection = new Set([...existingIslandData.regions].filter(x => currentIsland.has(x)));
        if (intersection.size === existingIslandData.regions.size) { // Means they are the same set of regions
          isDuplicateIsland = true;
          break;
        }
      }
    }

    if (!isDuplicateIsland) {
      newlyEncircledIslands.push({ regions: currentIsland, owner: currentOwner });
      currentIsland.forEach(rID => processedIslandRegionsTracker.add(rID));
    }
  }
}

// --- Part 2: Regions that *were* part of ownership transfers, and now don't touch same-owner regions ---
for (const regionID of allRegionIDsInMap) {
  const prevOwner = previousRegionOwners.has(regionID) ? previousRegionOwners.get(regionID) : "unowned";
  const currentOwner = currentRegionOwners.has(regionID) ? currentRegionOwners.get(regionID) : "unowned";

  // Only process regions that changed ownership AND are now owned (not unowned)
  if (prevOwner !== currentOwner && currentOwner !== "unowned") {
    // Check if this region is already part of an island from Part 1 calculation (should have been added to tracker)
    if (processedIslandRegionsTracker.has(regionID)) continue; 

    let hasSameOwnerNeighbor = false;
    const regionGeo = mapGeometry.geometry[regionID];
    if (regionGeo && Array.isArray(regionGeo.adjacencies)) {
      for (const adjID of regionGeo.adjacencies) {
        if (typeof adjID === 'string' && adjID.length > 0 && currentRegionOwners.get(adjID) === currentOwner) {
          hasSameOwnerNeighbor = true;
          break;
        }
      }
    }

    if (!hasSameOwnerNeighbor) {
      const newSingleRegionIsland = new Set([regionID]);
      newlyEncircledIslands.push({ regions: newSingleRegionIsland, owner: currentOwner });
      processedIslandRegionsTracker.add(regionID); // Mark as processed
    }
  }
}

if (newlyEncircledIslands.length === 0) {
  return "No newly created encirclements detected in this round based on definition.";
}

const resultSentences = [];

for (const islandData of newlyEncircledIslands) {
  const islandOwner = islandData.owner;
  const islandRegionNames = Array.from(islandData.regions)
    .map(rID => gameData.regionData?.[rID]?.name || rID) // Fallback to ID if name missing
    .sort();

  const borderingEntities = new Set();
  for (const rID of islandData.regions) {
    const regionGeo = mapGeometry.geometry[rID];
    if (regionGeo && Array.isArray(regionGeo.adjacencies)) {
      for (const adjID of regionGeo.adjacencies) {
        if (typeof adjID === 'string' && adjID.length > 0 && !islandData.regions.has(adjID)) {
          const adjOwner = currentRegionOwners.get(adjID) || "unowned";
          const adjRegionType = mapGeometry.geometry[adjID]?.type; // Get type for water detection

          if (adjRegionType === "Ocean" || adjRegionType === "Strait") {
            const adjRegionName = gameData.regionData?.[adjID]?.name || adjID;
            borderingEntities.add(`the water of ${adjRegionName}`);
          } else if (adjOwner !== islandOwner) {
            borderingEntities.add(adjOwner);
          }
        }
      }
    }
  }

  let borderingText = '';
  const borderingList = Array.from(borderingEntities).sort();
  if (borderingList.length > 0) {
    const last = borderingList.pop();
    if (borderingList.length > 0) {
      borderingText = ` and borders the countries/entities of ${borderingList.join(', ')} and ${last}`;
    } else {
      borderingText = ` and borders the country/entity of ${last}`;
    }
  }

  resultSentences.push(
    `An "island" owned by ${islandOwner} with the regions ${islandRegionNames.join(', ')} has been created${borderingText}.`
  );
}

if (resultSentences.length === 0) {
  return "No encirclement descriptions could be generated, possibly due to missing map data or unowned regions.";
}
return resultSentences.join('\n');

try {
