}

const consolidateStartRound = optionalData.consolidationStartRound;
const consolidateEndRound = optionalData.consolidationEndRound;

if (!consolidateStartRound || !consolidateEndRound) {
    return "Consolidation range not provided in optionalData.";
}

// Helper to convert a date string (YYYY-MM-DD AD/BC) or DateStructure to a sortable number
const getSortableDateValue = (date) => {
    if (typeof date === 'string') {
        const parts = date.match(/^(-?\d+)-(\d{2})-(\d{2})(?:\s(AD|BC))?$/);
        if (!parts) return -Infinity; // Invalid date string
        let year = parseInt(parts[1], 10);
        const month = parseInt(parts[2], 10);
        const day = parseInt(parts[3], 10);
        const label = parts[4];

        if (label === 'BC') {
            year = -year; // Represent BC years as negative for sorting
        }
        return year * 1000000 + month * 10000 + day * 100;
    } else if (typeof date === 'object' && date !== null && 'year' in date && 'month' in date && 'day' in date) {
        let year = date.year;
        if (date.label === 'BC') {
            year = -year;
        }
        return year * 1000000 + (date.month || 1) * 10000 + (date.day || 1) * 100;
    }
    return -Infinity; // Invalid date format
};

