const formatDate = (dateInput) => {
  let dateObj;
  if (typeof dateInput === 'string') {
    const parts = dateInput.split(' ');
    const dateParts = parts[0].split('-');
    dateObj = {
      year: parseInt(dateParts[0], 10),
      month: parseInt(dateParts[1], 10),
      day: parseInt(dateParts[2], 10),
      label: parts.length > 1 && (parts[1] === 'BC' || parts[1] === 'AD') ? parts[1] : 'AD'
    };
  } else if (dateInput && typeof dateInput === 'object') {
    dateObj = dateInput;
  } else {
    return '????-??-??';
  }

  const y = dateObj.year ?? '????';
  const m = String(dateObj.month ?? '??').padStart(2, '0');
  const d = String(dateObj.day ?? '??').padStart(2, '0');
  return `${y}-${m}-${d}${dateObj.label ? ' ' + dateObj.label : ''}`;
};

const parseDateForSort = (dateStringOrObject) => {
  let year, month, day, label;

  if (typeof dateStringOrObject === 'string') {
    const parts = dateStringOrObject.split(' ');
    const dateParts = parts[0].split('-');
    year = parseInt(dateParts[0], 10);
    month = parseInt(dateParts[1], 10);
    day = parseInt(dateParts[2], 10);
    label = parts.length > 1 && (parts[1] === 'BC' || parts[1] === 'AD') ? parts[1] : 'AD';
  } else if (dateStringOrObject && typeof dateStringOrObject === 'object') {
    year = dateStringOrObject.year;
    month = dateStringOrObject.month;
    day = dateStringOrObject.day;
    label = dateStringOrObject.label;
  } else {
    return -Infinity;
  }

  if (isNaN(year) || isNaN(month) || isNaN(day)) {
    return -Infinity;
  }

  let sortableYear = year;
  if (label === 'BC') {
    sortableYear = -(year - 1);
  }
  return sortableYear * 10000 + month * 100 + day;
};

