    ];
    const allMapChanges = allEventsInRound.flatMap(event => event.mapChanges || []);

    for (const change of allMapChanges) {
        switch (change.type) {
            case "createPolity":
                currentPolityRegions.set(change.polity.name, new Set());
                break;

            case "transferRegionOwnership":
                for (const transfer of change.transfers) {
                    for (const regionID of transfer.regionIDs) {
                        // Remove from old owner
                        currentPolityRegions.forEach((regions, polityName) => {
                            if (regions.has(regionID)) {
                                regions.delete(regionID);
                            }
                        });
                        // Add to new owner
                        if (transfer.toPolity !== null) {
                            if (!currentPolityRegions.has(transfer.toPolity)) {
                                currentPolityRegions.set(transfer.toPolity, new Set());
                            }
                            currentPolityRegions.get(transfer.toPolity).add(regionID);
                        }
                    }
                }
                break;

            case "dissolvePolity":
                // Remove polity and its regions
                currentPolityRegions.delete(change.polityName);
                currentPolityRegions.forEach(regions => {
                    for (const regionID of Array.from(regions)) {
                        if (getPolityForRegion(currentPolityRegions, regionID) === change.polityName) {
                            regions.delete(regionID);
                        }
                    }
                });
                break;

            case "updatePolity":
                const oldName = change.name;
                const newName = change.newName || oldName;
                if (oldName !== newName) {
                    const regions = currentPolityRegions.get(oldName) || new Set();
                    currentPolityRegions.delete(oldName);
                    currentPolityRegions.set(newName, regions);
                }
                if (change.setAdditionalNamesTo) {
                    // No direct state change for additionalNames in helper
                }
                if (change.color) {
                    // No direct state change for color in helper
                }
                break;

            case "createMapFeature":
                allFeatureNames.add(change.feature.name);
                currentMapFeatures.set(change.feature.name, { ...change.feature });
                const createLocation = change.feature.type === 'centroid' ? getRegionName(change.feature.location.regionID) : (change.feature.location.regionID ? getRegionName(change.feature.location.regionID) : 'an unknown location');
                featureChangesInRound.push(`Map feature "${change.feature.name}" was created in "${createLocation}".`);
                break;

            case "updateMapFeature":
                const existingFeature = currentMapFeatures.get(change.name);
                if (existingFeature) {
                    let moved = false;
                    let oldLocation = null;
                    if (change.properties.location && existingFeature.location) {
                        if (existingFeature.type === 'centroid' && change.properties.location.regionID !== existingFeature.location.regionID) {
                            oldLocation = getRegionName(existingFeature.location.regionID);
                            moved = true;
                        } else if (existingFeature.type === 'coordinate' && change.properties.location.regionID !== existingFeature.location.regionID) {
                            oldLocation = getRegionName(existingFeature.location.regionID);
                            moved = true;
                        }
                    }

                    currentMapFeatures.set(change.name, { ...existingFeature, ...change.properties });

                    if (moved) {
                        const newLocation = existingFeature.type === 'centroid' ? getRegionName(currentMapFeatures.get(change.name).location.regionID) : (currentMapFeatures.get(change.name).location.regionID ? getRegionName(currentMapFeatures.get(change.name).location.regionID) : 'an unknown location');
                        featureChangesInRound.push(`Map feature "${change.name}" moved from "${oldLocation}" to "${newLocation}".`);
                    }
                    // Other updates (scale, displaySymbol, etc.) are not specifically requested in the example output.
                }
                break;

            case "removeMapFeature":
                if (currentMapFeatures.has(change.name)) {
                    currentMapFeatures.delete(change.name);
                    featureChangesInRound.push(`Map feature "${change.name}" was dissolved.`);
                }
                break;
        }
    }

    // Compare polity regions at round start vs. current state (after all changes in the round)
    const regionsGainedByPolity = new Map(); // { polityName: Set<regionName> }
    const regionsLostByPolity = new Map();   // { polityName: Set<regionName> }

    const allPolitiesInvolved = new Set([...Array.from(polityRegionsAtRoundStart.keys()), ...Array.from(currentPolityRegions.keys())]);

    for (const polityName of allPolitiesInvolved) {
        const startRegions = polityRegionsAtRoundStart.get(polityName) || new Set();
        const endRegions = currentPolityRegions.get(polityName) || new Set();

        const gained = new Set([...endRegions].filter(rID => !startRegions.has(rID)).map(getRegionName));
        const lost = new Set([...startRegions].filter(rID => !endRegions.has(rID)).map(getRegionName));

        if (gained.size > 0) regionsGainedByPolity.set(polityName, gained);
        if (lost.size > 0) regionsLostByPolity.set(polityName, lost);
    }

    if (regionsGainedByPolity.size > 0 || regionsLostByPolity.size > 0) {
        roundOutput.push(`Round ${roundNum}:`);
        roundOutput.push(`The following polities received and lost regions:`);

        let hasTransfers = false;
        const allPolitiesWithTransfers = new Set([...regionsGainedByPolity.keys(), ...regionsLostByPolity.keys()]);

        for (const polityName of allPolitiesWithTransfers) {
            const gained = Array.from(regionsGainedByPolity.get(polityName) || new Set());
            const lost = Array.from(regionsLostByPolity.get(polityName) || new Set());

            let transferDesc = `"${polityName}"`;
            if (lost.length > 0) {
                transferDesc += ` lost "${lost.join('", "')}"`;
            }
            if (gained.length > 0 && lost.length > 0) {
                transferDesc += `. "${polityName}" received "${gained.join('", "')}".`;
            } else if (gained.length > 0) {
                transferDesc += ` received "${gained.join('", "')}".`;
            }

            if (gained.length > 0 || lost.length > 0) {
                roundOutput.push(transferDesc);
                hasTransfers = true;
            }
        }

        if (!hasTransfers) {
            roundOutput.push(`This round had no region transfers.`);
        }
    } else {
        roundOutput.push(`Round ${roundNum}:`);
        roundOutput.push(`This round had no region transfers.`);
    }

    roundOutput.push(`The following map feature changes occurred:`);
    if (featureChangesInRound.length > 0) {
        roundOutput.push(...featureChangesInRound);
    } else {
        roundOutput.push(`This round had no map feature changes.`);
    }

    allChanges.push(roundOutput.join('\n'));
}

// Helper to determine polity for a region (used when dissolving polities to ensure regions become unowned)
function getPolityForRegion(polityRegionsMap, regionId) {
    for (const [polity, regions] of polityRegionsMap.entries()) {
        if (regions.has(regionId)) {
            return polity;
        }
    }
    return null;
}

return allChanges.length > 0 ? allChanges.join('\n\n') : "No map changes recorded in completed rounds.";

const currentRoundData = gameData.rounds[String(currentRound)];
if (!currentRoundData) {
    return "No game data available for the current round.";
}

const countryDescriptions = currentRoundData.countryDescriptions;
const mapFeatures = currentRoundData.mapFeatures || {};
const regionNames = gameData.regionNames;

if (!countryDescriptions) {
    return "No country descriptions found for the current round.";
}

const allCountryNames = Object.keys(countryDescriptions);
const majorCountryNames = [];
const otherCountryNames = [];

const countryDataMap = {};

for (const countryName of allCountryNames) {
    const description = countryDescriptions[countryName];
    const ownedRegions = description.regionsOwned || [];

    const battalions = [];
    const cities = [];

    for (const featureID in mapFeatures) {
        const feature = mapFeatures[featureID];
        if (feature.ownerName === countryName) {
            if (feature.tags && feature.tags.includes("battalion")) {
                const regionName = regionNames[feature.location?.regionID] || feature.location?.regionID;
                battalions.push(`"${feature.name}" Stationed in the Region of "${regionName}"`);
            }
            if (feature.tags && feature.tags.includes("city")) {
                cities.push(`“${feature.name}”`);
            }
        }
    }

    countryDataMap[countryName] = {
        regions: ownedRegions.map(regionID => `"${regionNames[regionID] || regionID}"`),
        battalions: battalions,
        cities: cities
    };

    if (ownedRegions.length > 12) {
        majorCountryNames.push(countryName);
    } else {
        otherCountryNames.push(countryName);
    }
}

majorCountryNames.sort((a, b) => a.localeCompare(b));
otherCountryNames.sort((a, b) => a.localeCompare(b));

const sortedCountryNames = [...majorCountryNames, ...otherCountryNames];
let output = [];

for (const countryName of sortedCountryNames) {
    const data = countryDataMap[countryName];
    output.push(`"${countryName}":`);
    output.push(`All Owned Regions:`);
    output.push(data.regions.join(", "));

    output.push(`All Battalions:`);
    output.push(data.battalions.length > 0 ? data.battalions.join("\n") : `No Major Battalions Listed for "${countryName}"`);

    output.push(`All Cities:`);
    output.push(data.cities.length > 0 ? data.cities.join(", ") : `No Major Cities Listed for "${countryName}"`);
    output.push(""); 
}

return output.join("\n").trim();

if (!optionalData.chatID) return "";
const chat = gameData.rounds[currentRound]?.chats?.[optionalData.chatID];
if (!chat) return "";
return Object.entries(chat.messages ?? {})
  .sort(([a], [b]) => Number(a) - Number(b))
  .map(([_, m]) => `${m.senderName}: ${m.message}`)
  .join("\n");

const roundData = gameData.rounds[currentRound];
  if (!roundData || !roundData.countryDescriptions) {
    return "no territories";
  }
  const playerCountryName = gameData.playerCountry;
  const playerCountry = roundData.countryDescriptions[playerCountryName];
  if (!playerCountry || !playerCountry.regionsOwned || playerCountry.regionsOwned.length === 0) {
    return "no territories";
  }
  const regionNames = playerCountry.regionsOwned.map(regionId => {
    return gameData.regionNames[regionId] || regionId;
  });
  return regionNames.join(', ');

const prevRoundNum = currentRound - 1;
if (prevRoundNum < 1 || !gameData.rounds[String(prevRoundNum)]) {
  return "No previous round events available.";
}

const prevRound = gameData.rounds[String(prevRoundNum)];
let allEvents = [];

if (prevRound.eventsBetweenStartDateAndEndDate) {
  allEvents.push(...prevRound.eventsBetweenStartDateAndEndDate);
}

if (allEvents.length === 0) {
  return "No events found in the previous round.";
}

// Sort events chronologically by date
allEvents.sort((a, b) => {
  // Dates are in "YYYY-MM-DD" format, so string comparison works for chronological order
  return a.date.localeCompare(b.date);
});

const formattedEvents = allEvents.map(event => {
  const headline = event.title ? event.title : "No Headline";
  return `Headline: ${headline}\nDate: ${event.date}\nDescription: ${event.description}`;
}).join('\n\n');

return formattedEvents;
